// Extraer mensaje de WhatsApp Cloud API payload
const body = $input.first().json?.body || $input.first().json;
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;

// Filtrar status updates (delivered, read, etc.)
if (!value?.messages || value.messages.length === 0) {
  return [{ json: { skip: true, reason: 'status_update' } }];
}

const msg = value.messages[0];
const contact = value.contacts?.[0];
const msgType = msg.type;

let textoMensaje = '';
let interactiveId = '';
let interactiveType = '';

switch (msgType) {
  case 'text':
    textoMensaje = msg.text?.body || '';
    break;
  case 'interactive':
    if (msg.interactive?.button_reply) {
      textoMensaje = msg.interactive.button_reply.title || '';
      interactiveId = msg.interactive.button_reply.id || '';
      interactiveType = 'button_reply';
    } else if (msg.interactive?.list_reply) {
      textoMensaje = msg.interactive.list_reply.title || '';
      interactiveId = msg.interactive.list_reply.id || '';
      interactiveType = 'list_reply';
    }
    break;
  case 'button':
    textoMensaje = msg.button?.text || '';
    break;
  case 'audio':
  case 'image':
  case 'video':
  case 'document':
    textoMensaje = '__MEDIA__';
    break;
  default:
    textoMensaje = '__DESCONOCIDO__';
}

// Normalizar telefono argentino
let phone = msg.from;
if (!phone) return [{ json: { skip: true, reason: 'no_phone' } }];
if (phone.startsWith('54') && !phone.startsWith('549') && phone.length === 12) {
  phone = '549' + phone.substring(2);
}

// Log mensaje entrante
if (textoMensaje) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${$env.SUPABASE_URL}/rest/v1/consultorio_mensajes`,
      headers: { apikey: $env.SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$env.SUPABASE_SERVICE_KEY}`, 'Content-Type': 'application/json', Prefer: 'return=minimal' },
      body: JSON.stringify({ telefono_wa: phone, direccion: 'entrada', contenido: textoMensaje, estado_bot: null })
    });
  } catch(e) {}
}
return [{ json: {
  messageId: msg.id,
  timestamp: msg.timestamp,
  phone: phone,
  contactName: contact?.profile?.name || 'Desconocido',
  msgType: msgType,
  textoMensaje: textoMensaje,
  interactiveId: interactiveId,
  interactiveType: interactiveType,
  skip: false
} }];

const query = $input.first().json?.query || $input.first().json;
const mode = query?.['hub.mode'];
const token = query?.['hub.verify_token'];
const challenge = query?.['hub.challenge'];

// Verificar token (usar el mismo que configures en Meta)
const VERIFY_TOKEN = 'consultorio_demo_2026';

if (mode === 'subscribe' && token === VERIFY_TOKEN) {
  return [{ json: { challenge: challenge } }];
}

return [{ json: { error: 'Verification failed' } }];

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const phone = $input.first().json.phone;

// Buscar conversacion existente
let conv = null;
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
    qs: { telefono_wa: `eq.${phone}`, limit: '1' },
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
  });
  conv = res?.[0] || null;
} catch (err) {}

// Si no existe, crear
if (!conv) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
      headers: {
        'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json', 'Prefer': 'return=representation'
      },
      body: JSON.stringify({
        telefono_wa: phone,
        estado: 'inicio',
        contexto: {},
        handoff_humano: false
      })
    });
    conv = res?.[0] || { estado: 'inicio', contexto: {}, handoff_humano: false };
  } catch (err) {
    conv = { estado: 'inicio', contexto: {}, handoff_humano: false };
  }
}

// Safety net: if both GET and POST failed (Supabase down), use safe defaults
if (!conv) conv = { estado: 'inicio', contexto: {}, handoff_humano: false };

// Verificar sesion expirada (30 min sin actividad)
const lastUpdate = new Date(conv.updated_at || 0);
const now = new Date();
const diffMin = (now - lastUpdate) / 1000 / 60;

const ESTADOS_SIN_RESET = ['adelanto_pendiente', 'respuesta_reminder'];
if (diffMin > 30 && conv.estado !== 'inicio' && !conv.handoff_humano && !ESTADOS_SIN_RESET.includes(conv.estado)) {
  // Reset sesion expirada
  conv.estado = 'inicio';
  conv.contexto = {};
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
      qs: { telefono_wa: `eq.${phone}` },
      headers: {
        'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ estado: 'inicio', contexto: {}, updated_at: now.toISOString() })
    });
  } catch (err) {}
}

// Merge datos del mensaje con la conversacion
const msgData = $input.first().json;
return [{ json: {
  ...msgData,
  convEstado: conv.estado,
  convContexto: conv.contexto || {},
  convHandoff: conv.handoff_humano || false,
  convId: conv.id
} }];

// Reenviar mensaje del paciente a Telegram (handoff activo) - con reply threading
const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const TELEGRAM_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';
const TELEGRAM_CHAT = '6343825256';

if (!TELEGRAM_TOKEN) {
  return [{ json: { action: 'telegram_not_configured' } }];
}

const data = $input.first().json;
const ctx = data.convContexto || {};
const nombre = ctx.pacienteNombre || data.contactName || 'Paciente';
const texto = data.textoMensaje || '[sin texto]';

async function sendTG(text, replyToMsgId) {
  const payload = { chat_id: TELEGRAM_CHAT, text, parse_mode: 'HTML' };
  if (replyToMsgId) payload.reply_to_message_id = replyToMsgId;
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });
  const parsed = typeof resp === 'string' ? JSON.parse(resp) : resp;
  if (parsed?.ok !== true) throw new Error('TG API error: ' + JSON.stringify(parsed));
  return parsed?.result?.message_id || null;
}

async function saveCtx(phone, newCtx) {
  await helpers.httpRequest({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
    qs: { telefono_wa: `eq.${phone}` },
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ contexto: newCtx, updated_at: new Date().toISOString() })
  });
}

try {
  let tgMsgId = ctx.handoffTgMsgId || null;
  const newCtx = { ...ctx };

  if (ctx.handoffResumen) {
    // Primera vez: mandar alerta con instrucciones y capturar message_id
    const alertText = ctx.handoffResumen +
      '\n\n?? <b>Respond? este mensaje</b> para hablar con el paciente.\n? Respond? <code>/fin</code> para cerrar el handoff.';
    tgMsgId = await sendTG(alertText, null);
    if (tgMsgId) newCtx.handoffTgMsgId = tgMsgId;
    delete newCtx.handoffResumen;
    // Save context immediately to persist tgMsgId before any further sends
    try { await saveCtx(data.phone, newCtx); } catch(saveErr) { console.error('saveCtx failed:', saveErr?.message); }
  }

  // Reenviar mensaje del paciente como reply al alerta original
  await sendTG(`?? <b>${nombre}</b>:\n${texto}`, tgMsgId);
} catch(e) {}

return [{ json: { action: 'forwarded_to_telegram', phone: data.phone } }];
